gql:
query AlchemistDeposits($startDate: BigInt, $endDate: BigInt, $first: Int, $skip: Int) {
  alchemistDeposits(
    first: $first
    skip: $skip
    where: { timestamp_gte: $startDate, timestamp_lte: $endDate }
    orderBy: "timestamp"
    orderDirection: "asc"
  ) {
    id
    chain
    alchemist
    yieldToken
    sender
    amount
    timestamp
  }
}
